import Foundation
import ScanbotSDK

struct CroppingViewDefaultValues {
    let edgeColor = UIColor.white
    let edgeLineWidth: CGFloat = 2
    let edgeColorOnLine = UIColor.white
    let anchorPointsColors = UIColor.white
}

struct CroppingViewCroppedAreaResult: Codable {
    let polygon: [SBDPoint]
    let rotation: SBSDKImageRotation
    let sourceImage: SBSDKImageRef
}

@objcMembers
public class RNScanbotCroppingViewEventsDelegate: NSObject {
    
    private var onExtractedAreaCallback: ((String) -> Void)
    private var onErrorCallback: ((String) -> Void)
    
    @objc public init(onExtractArea: @escaping (String) -> Void, onError: @escaping (String) -> Void) {
        self.onExtractedAreaCallback = onExtractArea
        self.onErrorCallback = onError
    }
    
    @objc public func onExtractCroppingArea(_ json: String) {
        onExtractedAreaCallback(json)
    }
    
    @objc public func onError(_ json: String) {
        onErrorCallback(json)
    }
}

extension UIImage {
    static func placeholderImage(
        size: CGSize = CGSize(width: 100, height: 100),
        backgroundColor: UIColor = .black,
        cornerRadius: CGFloat = 8
    ) -> UIImage {
        let renderer = UIGraphicsImageRenderer(size: size)
        
        return renderer.image { context in
            let rect = CGRect(origin: .zero, size: size)
            let path = UIBezierPath(roundedRect: rect, cornerRadius: cornerRadius)
            backgroundColor.setFill()
            path.fill()
        }
    }
}

extension SBSDKImageEditingViewController {
    
    func setImage(image: UIImage) -> SBSDKImageEditingViewController {
        
        let newController = SBSDKImageEditingViewController.create(image: image, polygon: nil)
        
        newController.edgeColor = self.edgeColor
        newController.edgeLineWidth = self.edgeLineWidth
        newController.magneticEdgeColor = self.magneticEdgeColor
        newController.anchorPointsColor = self.anchorPointsColor
        newController.contentInsets = self.contentInsets
        
        return newController
    }
}

struct SBDPoint: Codable {
    let x: Double
    let y: Double
}

extension SBSDKPolygon {
    
    func polygonPoints() -> [SBDPoint] {
        (0..<4).compactMap {
            let point = normalizedPoint(with: UInt($0))
            return SBDPoint(x: point.x, y: point.y)
        }
    }
}
